import React, { useEffect, useRef } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (src && containerRef.current) {
      // Crear iframe de forma muy básica para evitar detección
      const frame = document.createElement('iframe');

      // Solo atributos esenciales
      frame.src = src;
      frame.width = '100%';
      frame.height = '100%';
      frame.allowFullscreen = true;

      // Estilos básicos sin transformaciones
      frame.style.cssText = `
        border: none;
        background: #000;
        border-radius: 8px;
        width: 100%;
        height: 100%;
      `;

      // Limpiar y agregar
      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      // No intentar inyectar CSS por CORS
      frame.onload = () => {
        console.log('Iframe cargado');
      };

      // Verificar si carga
      const checkLoad = setTimeout(() => {
        try {
          if (!frame.contentWindow) {
            console.log('Iframe no cargó correctamente');
            if (onError) onError();
          }
        } catch (e) {
          console.log('Error verificando iframe:', e.message);
          if (onError) onError();
        }
      }, 5000);

      return () => {
        clearTimeout(checkLoad);
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg relative overflow-hidden"
      style={{ 
        minHeight: '400px'
      }}
    >
      {/* Máscaras para bloquear anuncios */}
      <div className="absolute inset-0 pointer-events-none z-20">
        {/* Bloquear anuncios centrales */}
        <div 
          className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-80 h-60 bg-transparent"
          style={{
            background: 'linear-gradient(45deg, transparent 49%, #000 49%, #000 51%, transparent 51%)',
            pointerEvents: 'auto',
            zIndex: 30
          }}
          onClick={(e) => e.stopPropagation()}
        ></div>

        {/* Ocultar esquinas donde aparecen anuncios */}
        <div className="absolute top-0 right-0 w-32 h-32 bg-black"></div>
        <div className="absolute top-0 left-0 w-32 h-20 bg-black"></div>
        <div className="absolute bottom-0 left-0 w-full h-16 bg-black"></div>

        {/* Bloquear overlay de anuncios */}
        <div 
          className="absolute inset-0 bg-transparent"
          style={{ pointerEvents: 'auto' }}
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
            console.log('Anuncio bloqueado');
          }}
        ></div>
      </div>

      {/* Botón para cerrar anuncios */}
      <button
        className="absolute top-2 right-2 z-30 bg-red-600 hover:bg-red-700 text-white w-8 h-8 rounded-full text-xs font-bold"
        onClick={() => {
          // Intentar cerrar anuncios
          const iframe = containerRef.current?.querySelector('iframe');
          if (iframe) {
            try {
              iframe.contentWindow.postMessage('closeAd', '*');
            } catch (e) {
              console.log('No se pudo cerrar anuncio');
            }
          }
        }}
      >
        ×
      </button>
    </div>
  );
};

export default VideoFrame;
